@import "tailwindcss";

@layer theme {
  /* Light Theme (Default) */
  :root {
    /* Primary */
    --color-primary: #000000;
    --color-primary-foreground: #ffffff;

    /* Accent */
    --color-accent: #0d74ce;
    --color-accent-bright: #476cff;
    --color-accent-sky: #47c2ff;
    --color-accent-purple: #8145b5;

    /* Surface */
    --color-bg: #f0f0f3;
    --color-surface: #ffffff;
    --color-surface-elevated: #ffffff;

    /* Text */
    --color-text: #1c2024;
    --color-text-secondary: #60646c;
    --color-text-tertiary: #b0b4ba;

    /* Borders */
    --color-border: #e0e1e6;
    --color-border-input: #d9d9e0;

    /* Semantic */
    --color-success: #34c759;
    --color-warning: #ab6400;
    --color-destructive: #eb8e90;

    /* Shadows */
    --shadow-whisper: rgba(0, 0, 0, 0.08) 0px 3px 6px,
      rgba(0, 0, 0, 0.07) 0px 2px 4px;
    --shadow-elevated: rgba(0, 0, 0, 0.1) 0px 10px 20px,
      rgba(0, 0, 0, 0.05) 0px 3px 6px;

    /* Font families */
    --font-sans: var(--font-inter), -apple-system, system-ui, sans-serif;
    --font-mono: var(--font-jetbrains), ui-monospace, monospace;
  }

  /* Dark Theme */
  [data-theme="dark"] {
    /* Primary */
    --color-primary: #ffffff;
    --color-primary-foreground: #000000;

    /* Accent */
    --color-accent: #47c2ff;
    --color-accent-bright: #476cff;
    --color-accent-sky: #47c2ff;
    --color-accent-purple: #8145b5;

    /* Surface */
    --color-bg: #171717;
    --color-surface: #1a1a1a;
    --color-surface-elevated: #222222;

    /* Text */
    --color-text: #ffffff;
    --color-text-secondary: #b0b4ba;
    --color-text-tertiary: #60646c;

    /* Borders */
    --color-border: #363a3f;
    --color-border-input: #555860;

    /* Shadows */
    --shadow-whisper: rgba(0, 0, 0, 0.3) 0px 3px 6px,
      rgba(0, 0, 0, 0.2) 0px 2px 4px;
    --shadow-elevated: rgba(0, 0, 0, 0.4) 0px 10px 20px,
      rgba(0, 0, 0, 0.3) 0px 3px 6px;

    /* Semantic */
    --color-success: #30d158;
    --color-warning: #ffb340;
    --color-destructive: #ff6b6b;
  }
}

@layer base {
  * {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
  }

  html {
    scroll-behavior: smooth;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
  }

  body {
    font-family: var(--font-sans);
    background-color: var(--color-bg);
    color: var(--color-text);
    line-height: 1.5;
    min-height: 100vh;
    transition:
      background-color 0.3s ease,
      color 0.3s ease;
  }

  ::selection {
    background-color: var(--color-accent);
    color: white;
  }

  /* Scrollbar */
  ::-webkit-scrollbar {
    width: 8px;
    height: 8px;
  }

  ::-webkit-scrollbar-track {
    background: var(--color-bg);
  }

  ::-webkit-scrollbar-thumb {
    background: var(--color-border);
    border-radius: 4px;
  }

  ::-webkit-scrollbar-thumb:hover {
    background: var(--color-text-tertiary);
  }
}

@layer utilities {
  /* Animation utilities */
  .animate-fade-in {
    animation: fadeIn 0.6s ease-out forwards;
  }

  .animate-fade-in-up {
    animation: fadeInUp 0.6s ease-out forwards;
  }

  .animate-fade-in-left {
    animation: fadeInLeft 0.6s ease-out forwards;
  }

  .animate-stagger-1 {
    animation-delay: 100ms;
  }
  .animate-stagger-2 {
    animation-delay: 200ms;
  }
  .animate-stagger-3 {
    animation-delay: 300ms;
  }
  .animate-stagger-4 {
    animation-delay: 400ms;
  }
  .animate-stagger-5 {
    animation-delay: 500ms;
  }

  /* Reveal on scroll */
  .reveal {
    opacity: 0;
    transform: translateY(20px);
    transition:
      opacity 0.6s ease-out,
      transform 0.6s ease-out;
  }

  .reveal.visible {
    opacity: 1;
    transform: translateY(0);
  }

  /* Glass effect */
  .glass {
    background: rgba(255, 255, 255, 0.8);
    backdrop-filter: blur(12px);
    -webkit-backdrop-filter: blur(12px);
  }

  [data-theme="dark"] .glass {
    background: rgba(26, 26, 26, 0.8);
  }
}

@keyframes fadeIn {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(30px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes fadeInLeft {
  from {
    opacity: 0;
    transform: translateX(-30px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

/* Noise texture overlay */
.noise-overlay {
  position: relative;
}

.noise-overlay::before {
  content: "";
  position: absolute;
  inset: 0;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)'/%3E%3C/svg%3E");
  opacity: 0.03;
  pointer-events: none;
  z-index: 0;
}

[data-theme="dark"] .noise-overlay::before {
  opacity: 0.05;
}

/* Gradient mesh background */
.gradient-mesh {
  background:
    radial-gradient(at 20% 30%, var(--color-accent-sky) 0%, transparent 50%),
    radial-gradient(at 80% 70%, var(--color-accent-purple) 0%, transparent 50%),
    radial-gradient(at 50% 50%, var(--color-accent-bright) 0%, transparent 60%);
  opacity: 0.08;
}

[data-theme="dark"] .gradient-mesh {
  opacity: 0.15;
}

