export function Hero() {
  const { ref: titleRef, isVisible: titleVisible } = useScrollReveal<HTMLHeadingElement>();
  const { ref: subtitleRef, isVisible: subtitleVisible } = useScrollReveal<HTMLParagraphElement>();
  const { ref: actionsRef, isVisible: actionsVisible } = useScrollReveal<HTMLDivElement>();

  return (
    <section className="relative min-h-screen flex items-center justify-center pt-20 overflow-hidden noise-overlay">
      {/* Gradient mesh background */}
      <div className="absolute inset-0 gradient-mesh pointer-events-none" />

      {/* Grid pattern overlay */}
      <div
        className="
          absolute inset-0
          opacity-[0.02]
          dark:opacity-[0.05]
          pointer-events-none
         "
        style={{
          backgroundImage: `
            linear-gradient(var(--color-border) 1px, transparent 1px),
            linear-gradient(90deg, var(--color-border) 1px, transparent 1px)
          `,
          backgroundSize: "64px 64px",
        }}
      />

