          from-[var(--color-bg)] via-transparent to-[var(--color-bg)]
          pointer-events-none
        "
        style={{ zIndex: 1 }}
      />

      {/* Radial gradient accent */}
      <div
        className="
          absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2
          w-[800px] h-[800px]
          rounded-full
          bg-[radial-gradient(circle,_var(--color-accent-sky)_0%,_transparent_70%)]
          opacity-10
          blur-3xl
          pointer-events-none
        "
        style={{ zIndex: 0 }}
      />

      {/* Content */}
      <div
        className="
          relative
          max-w-5xl mx-auto
          px-6 lg:px-8
          text-center
          z-10
        "
      >
        {/* Badge */}
        <div
          className="
            inline-flex items-center gap-2
            px-4 py-2
            mb-8
            rounded-full
            bg-[var(--color-surface)]
            border border-[var(--color-border)]
            text-sm
            text-[var(--color-text-secondary)]
            animate-fade-in
          "
        >
          <span className="w-2 h-2 rounded-full bg-[var(--color-success)] animate-pulse" />
          Local-first AI gateway
        </div>

        {/* Headline */}
        <h1
          className="
            text-5xl sm:text-6xl lg:text-7xl
            font-bold
            leading-[1.1]
