          "
        >
          One Local API.
          <br />
          <span className="text-[var(--color-text-secondary)]">Every AI Provider.</span>
        </h1>

        {/* Subheadline */}
        <p
          className="
            mt-8
            text-lg sm:text-xl lg:text-2xl
            text-[var(--color-text-secondary)]
            max-w-2xl mx-auto
            leading-relaxed
            animate-fade-in-up
