            "animate-in",
            align === "right" ? "right-0" : "left-0",
          ].join(" ")}
          style={{ animationDuration: "150ms" }}
        >
          <div className="py-1">
            {items.map((item, index) => (
              <div key={index}>
                {item.href ? (
                  <a
                    href={item.href}
                    className={[
                      "block",
                      "px-4 py-3",
                      "hover:bg-[var(--color-surface-elevated)]",
                      "transition-colors duration-150",
                    ].join(" ")}
                    onClick={() => setIsOpen(false)}
                  >
                    <div className="text-body font-medium text-[var(--color-text)]">
                      {item.label}
                    </div>
                    {item.description && (
                      <div className="text-caption text-[var(--color-text-secondary)] mt-0.5">
                        {item.description}
                      </div>
                    )}
                  </a>
                ) : (
                  <button
                    onClick={() => {
                      item.onClick?.();
                      setIsOpen(false);
                    }}
                    className={[
                      "w-full text-left",
                      "px-4 py-3",
                      "hover:bg-[var(--color-surface-elevated)]",
                      "transition-colors duration-150",
                    ].join(" ")}
                  >
                    <div className="text-body font-medium text-[var(--color-text)]">
                      {item.label}
                    </div>
                    {item.description && (
                      <div className="text-caption text-[var(--color-text-secondary)] mt-0.5">
                        {item.description}
                      </div>
                    )}
                  </button>
                )}
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

